import{_ as d,b as a,e as o,al as i}from"./chunks/framework.aXkQZaJg.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"cd437382d5be1b6fdadbf4dbe507c2a9bacaeb41"};var e=new t.Error().stack;e&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[e]="1a5e09ec-8752-4d28-992a-2a1e68435c45",t._sentryDebugIdIdentifier="sentry-dbid-1a5e09ec-8752-4d28-992a-2a1e68435c45")}catch{}})();const s="/CoreFront-EndConcepts/img/gitFirst.png",n="/CoreFront-EndConcepts/img/gitSecond.png",x=JSON.parse('{"title":"Git 常用命令速查手册","description":"","frontmatter":{},"headers":[],"relativePath":"git/git.md","filePath":"git/git.md","lastUpdated":1782271806000}'),g={name:"git/git.md"};function r(t,e,l,c,h,f){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="git-常用命令速查手册" tabindex="-1">Git 常用命令速查手册 <a class="header-anchor" href="#git-常用命令速查手册" aria-label="Permalink to &quot;Git 常用命令速查手册&quot;">​</a></h1><p>本文档整理了 Git 的常用命令，按照功能进行分类，方便快速查阅。</p><h2 id="_1-仓库设置与初始化" tabindex="-1">1. 仓库设置与初始化 <a class="header-anchor" href="#_1-仓库设置与初始化" aria-label="Permalink to &quot;1. 仓库设置与初始化&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git init</code></td><td style="text-align:left;">在当前目录中创建一个新的 Git 仓库。</td></tr><tr><td style="text-align:left;"><code>git config --global credential.helper cache</code></td><td style="text-align:left;">设置凭证缓存，避免每次推送都输入密码。</td></tr></tbody></table><h2 id="_2-日常工作流程" tabindex="-1">2. 日常工作流程 <a class="header-anchor" href="#_2-日常工作流程" aria-label="Permalink to &quot;2. 日常工作流程&quot;">​</a></h2><h3 id="_2-1-状态检查与差异比较" tabindex="-1">2.1 状态检查与差异比较 <a class="header-anchor" href="#_2-1-状态检查与差异比较" aria-label="Permalink to &quot;2.1 状态检查与差异比较&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git status</code></td><td style="text-align:left;">检查当前工作目录和暂存区的状态（查看未跟踪、已修改、已暂存的文件）。</td></tr><tr><td style="text-align:left;"><code>git diff</code></td><td style="text-align:left;">查看<strong>工作目录</strong>中已修改但<strong>尚未暂存</strong>的文件与上次提交的差异。</td></tr><tr><td style="text-align:left;"><code>git diff --cached</code></td><td style="text-align:left;">查看<strong>暂存区</strong>中的文件与<strong>上次提交</strong>的差异。</td></tr><tr><td style="text-align:left;"><code>git diff --word-diff</code></td><td style="text-align:left;">在单词（Word）层面而不是行（Line）层面显示差异。</td></tr></tbody></table><h3 id="_2-2-暂存与提交" tabindex="-1">2.2 暂存与提交 <a class="header-anchor" href="#_2-2-暂存与提交" aria-label="Permalink to &quot;2.2 暂存与提交&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git add &lt;file&gt;</code></td><td style="text-align:left;">将指定文件的更改添加到暂存区（Stage）。</td></tr><tr><td style="text-align:left;"><code>git add .</code></td><td style="text-align:left;">将当前目录下所有已修改和新建的文件添加到暂存区。</td></tr><tr><td style="text-align:left;"><code>git commit</code></td><td style="text-align:left;">将暂存区的所有内容创建一个新的提交（会打开文本编辑器输入提交信息）。</td></tr><tr><td style="text-align:left;"><code>git commit -m &quot;message&quot;</code></td><td style="text-align:left;">提交并直接附上提交说明信息。</td></tr><tr><td style="text-align:left;"><code>git commit -a -m &quot;message&quot;</code></td><td style="text-align:left;">跳过 <code>git add</code> 步骤，直接将所有<strong>已跟踪</strong>文件的修改暂存并提交。</td></tr></tbody></table><h3 id="_2-3-文件操作" tabindex="-1">2.3 文件操作 <a class="header-anchor" href="#_2-3-文件操作" aria-label="Permalink to &quot;2.3 文件操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git rm &lt;file&gt;</code></td><td style="text-align:left;">从工作目录和暂存区中删除文件。</td></tr><tr><td style="text-align:left;"><code>git rm -f &lt;file&gt;</code></td><td style="text-align:left;">强制删除（当文件在暂存区有修改时使用）。</td></tr><tr><td style="text-align:left;"><code>git rm --cached &lt;file&gt;</code></td><td style="text-align:left;">仅从暂存区和版本库中删除，但保留工作目录中的文件（用于“反追踪”）。</td></tr><tr><td style="text-align:left;"><code>git mv &lt;old-name&gt; &lt;new-name&gt;</code></td><td style="text-align:left;">重命名文件或移动文件。</td></tr></tbody></table><h2 id="_3-查看历史与撤销操作" tabindex="-1">3. 查看历史与撤销操作 <a class="header-anchor" href="#_3-查看历史与撤销操作" aria-label="Permalink to &quot;3. 查看历史与撤销操作&quot;">​</a></h2><h3 id="_3-1-查看提交历史-git-log" tabindex="-1">3.1 查看提交历史 (<code>git log</code>) <a class="header-anchor" href="#_3-1-查看提交历史-git-log" aria-label="Permalink to &quot;3.1 查看提交历史 (`git log`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git log</code></td><td style="text-align:left;">显示完整的提交历史记录。</td></tr><tr><td style="text-align:left;"><code>git log -p -2</code></td><td style="text-align:left;">显示最近 2 次提交的详细差异（diff）。</td></tr><tr><td style="text-align:left;"><code>git log --stat</code></td><td style="text-align:left;">显示简要的增改行数统计。</td></tr><tr><td style="text-align:left;"><code>git log --pretty=oneline</code></td><td style="text-align:left;">将每个提交压缩到一行显示。</td></tr><tr><td style="text-align:left;"><code>git log --pretty=format:&quot;%h - %an, %ar : %s&quot;</code></td><td style="text-align:left;">自定义格式化输出。</td></tr><tr><td style="text-align:left;"><code>git log --since=2.weeks</code></td><td style="text-align:left;">仅显示最近两周内的提交。</td></tr><tr><td style="text-align:left;"><code>git log --author=&quot;nick&quot;</code></td><td style="text-align:left;">仅显示指定作者的提交。</td></tr><tr><td style="text-align:left;"><code>git log --grep=&quot;first commit&quot;</code></td><td style="text-align:left;">搜索提交信息中包含指定字符串的提交。</td></tr><tr><td style="text-align:left;"><code>git log --author=&quot;nick&quot; --grep=&quot;first&quot; --all-match</code></td><td style="text-align:left;">同时满足多个筛选条件（<code>--all-match</code> 表示 AND 关系）。</td></tr><tr><td style="text-align:left;"><code>git reflog</code></td><td style="text-align:left;">查看所有分支的所有操作记录，包括已被删除的 commit 和 reset 操作（用于“后悔药”）。</td></tr></tbody></table><h3 id="_3-2-撤销与重置" tabindex="-1">3.2 撤销与重置 <a class="header-anchor" href="#_3-2-撤销与重置" aria-label="Permalink to &quot;3.2 撤销与重置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git commit --amend</code></td><td style="text-align:left;">修改<strong>最后一次</strong>提交（可以修改提交信息或追加文件）。</td></tr><tr><td style="text-align:left;"><code>git reset HEAD &lt;file&gt;</code></td><td style="text-align:left;">将文件从<strong>暂存区</strong>撤销，但保留工作目录中的修改（<code>git add</code> 的反操作）。</td></tr><tr><td style="text-align:left;"><code>git restore --staged &lt;file&gt;</code></td><td style="text-align:left;">同上，新版 Git 推荐用法。</td></tr><tr><td style="text-align:left;"><code>git checkout -- &lt;file&gt;</code></td><td style="text-align:left;"><strong>丢弃</strong>工作目录中对文件的修改，恢复到最近一次提交的状态。</td></tr><tr><td style="text-align:left;"><code>git restore &lt;file&gt;</code></td><td style="text-align:left;">同上，新版 Git 推荐用法。<strong>此操作会丢失修改！</strong></td></tr><tr><td style="text-align:left;"><code>git reset --soft HEAD^</code></td><td style="text-align:left;">撤销上一次 <code>commit</code>，但保留暂存区和工作目录的更改。</td></tr><tr><td style="text-align:left;"><code>git reset --mixed HEAD^</code></td><td style="text-align:left;"><strong>(默认)</strong> 撤销上一次 <code>commit</code>，保留工作目录的更改，但清空暂存区。</td></tr><tr><td style="text-align:left;"><code>git reset --hard HEAD^</code></td><td style="text-align:left;"><strong>(危险)</strong> 彻底撤销上一次 <code>commit</code>，暂存区和工作目录都将回滚。</td></tr></tbody></table><h2 id="_4-远程仓库操作" tabindex="-1">4. 远程仓库操作 <a class="header-anchor" href="#_4-远程仓库操作" aria-label="Permalink to &quot;4. 远程仓库操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git remote -v</code></td><td style="text-align:left;">查看已配置的远程仓库及其 URL。</td></tr><tr><td style="text-align:left;"><code>git remote add &lt;name&gt; &lt;url&gt;</code></td><td style="text-align:left;">添加一个新的远程仓库。</td></tr><tr><td style="text-align:left;"><code>git remote show &lt;name&gt;</code></td><td style="text-align:left;">查看指定远程仓库的详细信息。</td></tr><tr><td style="text-align:left;"><code>git remote rename &lt;old&gt; &lt;new&gt;</code></td><td style="text-align:left;">重命名远程仓库。</td></tr><tr><td style="text-align:left;"><code>git remote rm &lt;name&gt;</code></td><td style="text-align:left;">删除指定的远程仓库。</td></tr><tr><td style="text-align:left;"><code>git fetch &lt;remote&gt; &lt;branch&gt;</code></td><td style="text-align:left;">从远程仓库抓取更新，但<strong>不</strong>自动合并到本地分支。</td></tr><tr><td style="text-align:left;"><code>git pull &lt;remote&gt; &lt;branch&gt;</code></td><td style="text-align:left;">从远程仓库抓取更新并<strong>自动合并</strong>到当前本地分支 (<code>fetch</code> + <code>merge</code>)。</td></tr><tr><td style="text-align:left;"><code>git push &lt;remote&gt; &lt;branch&gt;</code></td><td style="text-align:left;">将本地分支的提交推送到远程仓库。</td></tr><tr><td style="text-align:left;"><code>git push origin --delete &lt;branch&gt;</code></td><td style="text-align:left;">删除一个远程分支。</td></tr><tr><td style="text-align:left;"><code>git fetch --all &amp;&amp; git reset --hard origin/master &amp;&amp; git pull</code></td><td style="text-align:left;"><strong>(危险)</strong> 强制用远程分支覆盖本地分支。</td></tr></tbody></table><h2 id="_5-分支管理" tabindex="-1">5. 分支管理 <a class="header-anchor" href="#_5-分支管理" aria-label="Permalink to &quot;5. 分支管理&quot;">​</a></h2><h3 id="_5-1-本地分支" tabindex="-1">5.1 本地分支 <a class="header-anchor" href="#_5-1-本地分支" aria-label="Permalink to &quot;5.1 本地分支&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git branch &lt;name&gt;</code></td><td style="text-align:left;">创建一个新分支。</td></tr><tr><td style="text-align:left;"><code>git branch</code></td><td style="text-align:left;">列出所有本地分支。</td></tr><tr><td style="text-align:left;"><code>git branch -v</code></td><td style="text-align:left;">查看各分支的最后一个提交信息。</td></tr><tr><td style="text-align:left;"><code>git checkout &lt;name&gt;</code></td><td style="text-align:left;">切换到指定分支。</td></tr><tr><td style="text-align:left;"><code>git checkout -b &lt;name&gt;</code></td><td style="text-align:left;">创建并立即切换到新分支。</td></tr><tr><td style="text-align:left;"><code>git branch -d &lt;name&gt;</code></td><td style="text-align:left;">删除一个<strong>已合并</strong>的分支。</td></tr><tr><td style="text-align:left;"><code>git branch -D &lt;name&gt;</code></td><td style="text-align:left;"><strong>强制</strong>删除一个分支（无论是否已合并）。</td></tr><tr><td style="text-align:left;"><code>git branch --merged</code></td><td style="text-align:left;">查看哪些分支已被合并到当前分支。</td></tr><tr><td style="text-align:left;"><code>git branch --no-merged</code></td><td style="text-align:left;">查看哪些分支尚未被合并到当前分支。</td></tr></tbody></table><h3 id="_5-2-跟踪分支" tabindex="-1">5.2 跟踪分支 <a class="header-anchor" href="#_5-2-跟踪分支" aria-label="Permalink to &quot;5.2 跟踪分支&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git checkout --track origin/serverfix</code></td><td style="text-align:left;">创建并跟踪一个远程分支（本地分支名与远程同名）。</td></tr><tr><td style="text-align:left;"><code>git checkout -b sf origin/serverfix</code></td><td style="text-align:left;">创建本地分支 <code>sf</code> 并跟踪远程分支 <code>origin/serverfix</code>。</td></tr><tr><td style="text-align:left;"><code>git branch -u origin/serverfix</code></td><td style="text-align:left;">为当前分支设置上游（跟踪）分支。</td></tr><tr><td style="text-align:left;"><code>git branch --set-upstream-to=origin/serverfix</code></td><td style="text-align:left;">同上。</td></tr><tr><td style="text-align:left;"><code>git branch -vv</code></td><td style="text-align:left;">查看本地分支与所跟踪的远程分支的关联状态。</td></tr></tbody></table><h3 id="_5-3-变基-rebase" tabindex="-1">5.3 变基 (<code>rebase</code>) <a class="header-anchor" href="#_5-3-变基-rebase" aria-label="Permalink to &quot;5.3 变基 (`rebase`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git rebase &lt;basebranch&gt;</code></td><td style="text-align:left;">将当前分支的提交“变基”到 <code>&lt;basebranch&gt;</code> 的顶端，使历史记录更线性。</td></tr><tr><td style="text-align:left;"><code>git rebase &lt;base&gt; &lt;topic&gt;</code></td><td style="text-align:left;">将 <code>&lt;topic&gt;</code> 分支变基到 <code>&lt;base&gt;</code> 分支上。</td></tr></tbody></table><h2 id="_6-标签管理-tag" tabindex="-1">6. 标签管理 (<code>tag</code>) <a class="header-anchor" href="#_6-标签管理-tag" aria-label="Permalink to &quot;6. 标签管理 (`tag`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git tag</code></td><td style="text-align:left;">列出所有标签。</td></tr><tr><td style="text-align:left;"><code>git tag -l &#39;v1.4.2.*&#39;</code></td><td style="text-align:left;">使用通配符搜索标签。</td></tr><tr><td style="text-align:left;"><code>git tag -a v1.4 -m &quot;message&quot;</code></td><td style="text-align:left;">创建一个带附注的标签（推荐）。</td></tr><tr><td style="text-align:left;"><code>git tag -s v1.5 -m &quot;message&quot;</code></td><td style="text-align:left;">创建一个 GPG 签名的标签。</td></tr><tr><td style="text-align:left;"><code>git tag -v &lt;tag-name&gt;</code></td><td style="text-align:left;">验证一个 GPG 签名标签。</td></tr><tr><td style="text-align:left;"><code>git show &lt;tag-name&gt;</code></td><td style="text-align:left;">查看标签信息和对应的提交信息。</td></tr><tr><td style="text-align:left;"><code>git tag -a v1.2 &lt;commit-hash&gt;</code></td><td style="text-align:left;">对过去的某个提交追加标签。</td></tr><tr><td style="text-align:left;"><code>git push origin &lt;tag-name&gt;</code></td><td style="text-align:left;">将指定标签推送到远程仓库。</td></tr><tr><td style="text-align:left;"><code>git push origin --tags</code></td><td style="text-align:left;">将所有本地新增的标签一次性推送到远程仓库。</td></tr></tbody></table><h2 id="_7-高级工具" tabindex="-1">7. 高级工具 <a class="header-anchor" href="#_7-高级工具" aria-label="Permalink to &quot;7. 高级工具&quot;">​</a></h2><h3 id="_7-1-贮藏-stash" tabindex="-1">7.1 贮藏 (<code>stash</code>) <a class="header-anchor" href="#_7-1-贮藏-stash" aria-label="Permalink to &quot;7.1 贮藏 (`stash`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git stash</code></td><td style="text-align:left;">将工作目录中未提交的修改（已跟踪文件）临时保存起来。</td></tr><tr><td style="text-align:left;"><code>git stash list</code></td><td style="text-align:left;">查看所有贮藏记录。</td></tr><tr><td style="text-align:left;"><code>git stash apply stash@{2}</code></td><td style="text-align:left;">应用指定的贮藏，但<strong>不</strong>从列表中移除。</td></tr><tr><td style="text-align:left;"><code>git stash pop</code></td><td style="text-align:left;">应用最近的贮藏，并从列表中<strong>移除</strong>。</td></tr><tr><td style="text-align:left;"><code>git stash drop stash@{2}</code></td><td style="text-align:left;">丢弃指定的贮藏。</td></tr><tr><td style="text-align:left;"><code>git stash -u</code> 或 <code>--include-untracked</code></td><td style="text-align:left;">贮藏时同时包含未跟踪的文件。</td></tr><tr><td style="text-align:left;"><code>git stash -a</code> 或 <code>--all</code></td><td style="text-align:left;">贮藏时同时包含所有文件（包括忽略的文件）。</td></tr><tr><td style="text-align:left;"><code>git stash branch &lt;new-branch&gt;</code></td><td style="text-align:left;">基于指定的贮藏创建一个新分支。</td></tr></tbody></table><h3 id="_7-2-清理-clean" tabindex="-1">7.2 清理 (<code>clean</code>) <a class="header-anchor" href="#_7-2-清理-clean" aria-label="Permalink to &quot;7.2 清理 (`clean`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git clean -n</code></td><td style="text-align:left;"><strong>演习</strong>：显示将要被移除的未跟踪文件。</td></tr><tr><td style="text-align:left;"><code>git clean -f</code></td><td style="text-align:left;"><strong>(危险)</strong> 强制移除工作目录中所有未跟踪的文件。</td></tr><tr><td style="text-align:left;"><code>git clean -f -d</code></td><td style="text-align:left;"><strong>(危险)</strong> 同时移除未跟踪的文件和空目录。</td></tr></tbody></table><h3 id="_7-3-改写历史-filter-branch-filter-repo" tabindex="-1">7.3 改写历史 (<code>filter-branch</code> / <code>filter-repo</code>) <a class="header-anchor" href="#_7-3-改写历史-filter-branch-filter-repo" aria-label="Permalink to &quot;7.3 改写历史 (`filter-branch` / `filter-repo`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>git filter-branch --tree-filter &#39;cmd&#39;</code></td><td style="text-align:left;"><strong>(已过时)</strong> 对每个提交执行指定命令来改写历史。</td></tr><tr><td style="text-align:left;"><code>git filter-repo</code></td><td style="text-align:left;"><strong>(推荐)</strong> 新一代工具，用于批量改写历史，更安全、更快速。</td></tr><tr><td style="text-align:left;"><code>git filter-branch --tree-filter &#39;rm -f passwords.txt&#39; HEAD</code></td><td style="text-align:left;">示例：从所有提交中移除 <code>passwords.txt</code> 文件。</td></tr></tbody></table><h3 id="_7-4-其他" tabindex="-1">7.4 其他 <a class="header-anchor" href="#_7-4-其他" aria-label="Permalink to &quot;7.4 其他&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>.gitignore</code></td><td style="text-align:left;">文件，用于指定 Git 应该忽略的文件或目录模式（如 <code>*.log</code>, <code>/node_modules</code>）。</td></tr></tbody></table><p><img src="'+s+'" alt="Logo" data-zoomable="true"><img src="'+n+`" alt="Logo" data-zoomable="true"></p><h2 id="_8-应用场景" tabindex="-1">8. 应用场景 <a class="header-anchor" href="#_8-应用场景" aria-label="Permalink to &quot;8. 应用场景&quot;">​</a></h2><h3 id="_8-1-初始化一个新项目" tabindex="-1">8.1 初始化一个新项目 <a class="header-anchor" href="#_8-1-初始化一个新项目" aria-label="Permalink to &quot;8.1 初始化一个新项目&quot;">​</a></h3><p>当你开始一个全新的项目，并希望使用 Git 来管理其版本时。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>git init</code></strong></td><td style="text-align:left;">在当前项目文件夹中创建一个新的 Git 仓库。这会生成一个隐藏的 <code>.git</code> 目录，它包含了仓库所有必要的文件和元数据。</td></tr><tr><td style="text-align:left;"><strong><code>git add &lt;file&gt;</code></strong></td><td style="text-align:left;">将文件的当前版本添加到“暂存区”（Staging Area）。暂存区像是一个快照的草稿箱，你可以把这次想提交的全部修改都放进去。使用 <code>git add .</code> 可以暂存所有已修改和新建的文件。</td></tr><tr><td style="text-align:left;"><strong><code>git commit -m &quot;提交信息&quot;</code></strong></td><td style="text-align:left;">将暂存区的所有内容创建成一个新的“提交”（Commit），并永久保存在你的本地仓库历史中。提交信息应当清晰地描述这次提交所做的更改。</td></tr><tr><td style="text-align:left;"><strong><code>git status</code></strong></td><td style="text-align:left;">这是你最常使用的命令之一。它会显示你的工作目录和暂存区的状态，告诉你哪些文件被修改了、哪些文件还未被 Git 追踪、哪些文件已暂存等。</td></tr></tbody></table><p><strong>应用流程：</strong></p><ol><li>在你的项目根目录运行 <code>git init</code>。</li><li>编写代码，创建文件。</li><li>运行 <code>git status</code> 查看文件状态，它们会显示为 &quot;untracked files&quot;（未追踪的文件）。</li><li>使用 <code>git add &lt;文件名&gt;</code> 或 <code>git add .</code> 将你的新文件和修改添加到暂存区。</li><li>再次运行 <code>git status</code>，文件会显示为 &quot;changes to be committed&quot;（待提交的更改）。</li><li>使用 <code>git commit -m &quot;Initial commit&quot;</code> 提交你的第一个版本。</li></ol><h3 id="_8-2-进行日常开发-分支、修改、提交" tabindex="-1">8.2 进行日常开发（分支、修改、提交） <a class="header-anchor" href="#_8-2-进行日常开发-分支、修改、提交" aria-label="Permalink to &quot;8.2 进行日常开发（分支、修改、提交）&quot;">​</a></h3><p>在项目中开发新功能或修复 Bug 时，最佳实践是使用“分支”（Branch）来隔离你的工作，以免影响主线（<code>main</code> 或 <code>master</code>）。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>git branch</code></strong></td><td style="text-align:left;">不带参数时，列出所有本地分支，并用 <code>*</code> 标记出你当前所在的分支。</td></tr><tr><td style="text-align:left;"><strong><code>git branch &lt;分支名&gt;</code></strong></td><td style="text-align:left;">创建一个新分支，但不会自动切换过去。</td></tr><tr><td style="text-align:left;"><strong><code>git checkout &lt;分支名&gt;</code></strong></td><td style="text-align:left;">切换到指定的分支。你的工作目录中的文件会自动更新为该分支最后一次提交时的状态。</td></tr><tr><td style="text-align:left;"><strong><code>git checkout -b &lt;分支名&gt;</code></strong></td><td style="text-align:left;">这是一个常用组合，它会 <strong>创建</strong> 一个新分支并 <strong>立即切换</strong> 过去。相当于 <code>git branch &lt;分支名&gt;</code> + <code>git checkout &lt;分支名&gt;</code>。</td></tr><tr><td style="text-align:left;"><strong><code>git merge &lt;分支名&gt;</code></strong></td><td style="text-align:left;">将指定分支的历史合并到你当前所在的分支。例如，在 <code>main</code> 分支上运行 <code>git merge feature-x</code> 会将 <code>feature-x</code> 分支上的所有提交合并到 <code>main</code> 分支。</td></tr><tr><td style="text-align:left;"><strong><code>git branch -d &lt;分支名&gt;</code></strong></td><td style="text-align:left;">删除一个已经合并过的分支。如果分支还没合并，Git 会提示你，你可以使用 <code>-D</code> (大写) 来强制删除。</td></tr></tbody></table><p><strong>应用流程：</strong></p><ol><li>假设你要开发一个“用户登录”功能，首先从 <code>main</code> 分支创建并切换到一个新分支：<code>git checkout -b feature-login</code>。</li><li>在这个 <code>feature-login</code> 分支上，进行代码编写、修改文件。</li><li>像场景一那样，周期性地使用 <code>git add .</code> 和 <code>git commit -m &quot;Added login form&quot;</code> 来保存你的进度。</li><li>功能开发完毕后，切回主分支：<code>git checkout main</code>。</li><li>将你的功能分支合并到主分支：<code>git merge feature-login</code>。</li><li>合并成功后，可以删除不再需要的功能分支：<code>git branch -d feature-login</code>。</li></ol><h3 id="_8-3-与团队协作-远程仓库" tabindex="-1">8.3 与团队协作（远程仓库） <a class="header-anchor" href="#_8-3-与团队协作-远程仓库" aria-label="Permalink to &quot;8.3 与团队协作（远程仓库）&quot;">​</a></h3><p>当多人共同开发一个项目时，就需要一个中央仓库（如 GitHub, GitLab）来同步彼此的工作。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>git clone &lt;仓库URL&gt;</code></strong></td><td style="text-align:left;">从远程服务器下载一个项目的完整拷贝，包括所有历史记录。这是你加入一个现有项目时的第一步。</td></tr><tr><td style="text-align:left;"><strong><code>git remote -v</code></strong></td><td style="text-align:left;">查看你配置的远程仓库地址。<code>origin</code> 是 <code>git clone</code> 时为你创建的默认远程仓库名。</td></tr><tr><td style="text-align:left;"><strong><code>git pull</code></strong></td><td style="text-align:left;">从远程仓库 <strong>拉取</strong> 最新的更改并自动与你当前的分支 <strong>合并</strong>。这是保持本地代码同步的常用方法。它相当于 <code>git fetch</code> + <code>git merge</code>。</td></tr><tr><td style="text-align:left;"><strong><code>git fetch</code></strong></td><td style="text-align:left;">仅从远程仓库 <strong>拉取</strong> 最新的更改，但 <strong>不</strong> 会自动合并。这让你可以在合并前先查看远程的变动。</td></tr><tr><td style="text-align:left;"><strong><code>git push</code></strong></td><td style="text-align:left;">将你本地的提交 <strong>推送</strong> 到远程仓库，与团队分享你的工作。</td></tr><tr><td style="text-align:left;"><strong><code>git push -u origin &lt;分支名&gt;</code></strong></td><td style="text-align:left;">当你第一次推送一个新创建的本地分支时，使用 <code>-u</code> 参数可以将其与远程的同名分支关联起来。之后你在这个分支上只需运行 <code>git push</code> 即可。</td></tr></tbody></table><p><strong>应用流程：</strong></p><ol><li><strong>开始工作前</strong>：运行 <code>git pull</code>，确保你的本地 <code>main</code> 分支是最新版本。</li><li><strong>开发新功能</strong>：按照场景二，创建 <code>feature-x</code> 分支并进行开发和提交。</li><li><strong>分享你的分支</strong>：运行 <code>git push -u origin feature-x</code>，将你的功能分支推送到远程，这样其他人也能看到你的进度或进行代码审查。</li><li><strong>功能完成并合并到 main 后</strong>：在本地 <code>main</code> 分支上，运行 <code>git push</code>，将合并后的 <code>main</code> 分支推送到远程，更新项目主线。</li></ol><h3 id="_8-4-查看历史与撤销操作" tabindex="-1">8.4 查看历史与撤销操作 <a class="header-anchor" href="#_8-4-查看历史与撤销操作" aria-label="Permalink to &quot;8.4 查看历史与撤销操作&quot;">​</a></h3><p>有时候你需要查看过去的提交记录，或者撤销一些不满意的修改。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>git log</code></strong></td><td style="text-align:left;">显示从最新到最旧的提交历史。每个提交都包含作者、日期、提交信息和唯一的 SHA-1 哈希值。</td></tr><tr><td style="text-align:left;"><strong><code>git log --oneline --graph</code></strong></td><td style="text-align:left;"><code>log</code> 命令有很多强大的参数。<code>--oneline</code> 会将每个提交压缩为一行显示；<code>--graph</code> 会用 ASCII 图形展示分支的合并历史。</td></tr><tr><td style="text-align:left;"><strong><code>git diff</code></strong></td><td style="text-align:left;">查看 <strong>尚未暂存</strong> 的文件修改内容。</td></tr><tr><td style="text-align:left;"><strong><code>git diff --staged</code></strong></td><td style="text-align:left;">查看 <strong>已经暂存但尚未提交</strong> 的文件修改内容。</td></tr><tr><td style="text-align:left;"><strong><code>git reset &lt;文件&gt;</code></strong></td><td style="text-align:left;">将文件从暂存区 <strong>移出</strong>，但保留工作目录中的修改。用于撤销 <code>git add</code>。</td></tr><tr><td style="text-align:left;"><strong><code>git checkout -- &lt;文件&gt;</code></strong></td><td style="text-align:left;"><strong>彻底丢弃</strong> 工作目录中对某个文件的修改，将其恢复到最近一次提交时的状态。<strong>这是一个危险操作，修改会丢失！</strong></td></tr><tr><td style="text-align:left;"><strong><code>git revert &lt;提交哈希&gt;</code></strong></td><td style="text-align:left;">创建一个新的提交，内容与指定的旧提交 <strong>完全相反</strong>，从而“撤销”该次提交的效果。这是在公共历史中安全撤销更改的首选方式。</td></tr></tbody></table><p><strong>应用流程：</strong></p><ul><li><strong>&quot;我 add 错文件了！&quot;</strong>：运行 <code>git reset &lt;文件名&gt;</code>。</li><li><strong>&quot;我把这个文件改乱了，想回到最初的版本！&quot;</strong>：运行 <code>git checkout -- &lt;文件名&gt;</code>。</li><li><strong>&quot;这个功能上线后发现有 Bug，需要紧急撤销！&quot;</strong>：找到引入 Bug 的那个提交的哈希值（通过 <code>git log</code>），然后运行 <code>git revert &lt;提交哈希&gt;</code>，再 <code>git push</code>。</li></ul><h3 id="_8-5-解决冲突" tabindex="-1">8.5 解决冲突 <a class="header-anchor" href="#_8-5-解决冲突" aria-label="Permalink to &quot;8.5 解决冲突&quot;">​</a></h3><p><strong>冲突是如何产生的？</strong></p><ol><li>你和你的同事都修改了同一个文件 <code>style.css</code> 的第 10 行。</li><li>你的同事先将他的修改推送到了 <code>main</code> 分支。</li><li>你尝试 <code>git pull</code> 或 <code>git merge main</code> 来更新你的代码，此时冲突就发生了。</li></ol><p><strong>解决冲突的详细步骤</strong></p><p>假设你当前在 <code>feature</code> 分支，想要合并 <code>main</code> 分支的更新，运行 <code>git merge main</code> 后，终端提示冲突。</p><table tabindex="0"><thead><tr><th style="text-align:left;">步骤</th><th style="text-align:left;">命令</th><th style="text-align:left;">详细说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1. 识别冲突文件</strong></td><td style="text-align:left;"><code>git status</code></td><td style="text-align:left;">终端会明确告诉你合并失败。运行 <code>git status</code>，你会看到一个名为 “Unmerged paths”（未合并的路径）的列表，这里列出了所有包含冲突的文件。</td></tr><tr><td style="text-align:left;"><strong>2. 打开冲突文件</strong></td><td style="text-align:left;">(使用你的代码编辑器)</td><td style="text-align:left;">打开任何一个冲突的文件，你会看到类似下面的特殊标记，它们将不同分支的修改包裹了起来。</td></tr><tr><td style="text-align:left;"><strong>3. 手动解决冲突</strong></td><td style="text-align:left;">(编辑文件)</td><td style="text-align:left;">这是核心步骤。你需要<strong>手动编辑文件</strong>，删除 Git 添加的特殊标记，并决定最终要保留的代码。</td></tr><tr><td style="text-align:left;"><strong>4. 标记为已解决</strong></td><td style="text-align:left;"><code>git add &lt;文件名&gt;</code></td><td style="text-align:left;">在你确认一个文件已经修改完毕、冲突已解决后，使用 <code>git add</code> 命令来告诉 Git：“这个文件我已经处理好了。”</td></tr><tr><td style="text-align:left;"><strong>5. 完成合并</strong></td><td style="text-align:left;"><code>git commit</code></td><td style="text-align:left;">当所有冲突文件都通过 <code>git add</code> 标记为已解决后，运行 <code>git commit</code>。Git 会自动生成一个合并提交信息，你只需保存并关闭编辑器即可完成整个合并过程。</td></tr></tbody></table><p><strong>如何编辑冲突文件</strong> 当你打开冲突文件时，会看到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</span></span>
<span class="line"><span>// 这是你当前分支（HEAD）所做的修改</span></span>
<span class="line"><span>const color = &quot;blue&quot;;</span></span>
<span class="line"><span>=======</span></span>
<span class="line"><span>// 这是你正在合并进来的那个分支所做的修改</span></span>
<span class="line"><span>const color = &quot;red&quot;;</span></span>
<span class="line"><span>&gt;&gt;&gt;&gt;&gt;&gt;&gt; main</span></span></code></pre></div><ul><li><code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</code> 到 <code>=======</code> 之间的内容，是你<strong>当前所在分支</strong>的修改。</li><li><code>=======</code> 到 <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt; &lt;分支名&gt;</code> 之间的内容，是你<strong>要合并进来的那个分支</strong>的修改。</li></ul><p><strong>你有以下几种选择来解决它：</strong></p><ol><li><strong>保留你的修改</strong>：删除 <code>=======</code> 到 <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt; main</code> 的所有内容，并删掉标记。<div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 决定保留蓝色</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;blue&#39;</span></span></code></pre></div></li><li><strong>接受别人的修改</strong>：删除 <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</code> 到 <code>=======</code> 的所有内容，并删掉标记。<div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 决定接受红色</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;red&#39;</span></span></code></pre></div></li><li><strong>保留双方的修改</strong>：根据需要，同时保留两部分代码。<div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 决定两个颜色都保留</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> primaryColor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;blue&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> alertColor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;red&#39;</span></span></code></pre></div></li><li><strong>进行全新的修改</strong>：删除所有标记，并写入全新的、你认为最合适的代码。 <code>js // 决定使用一个全新的颜色 const themeColor = &quot;purple&quot;; </code><strong>关键在于：</strong> 最终的文件内容必须是你期望的样子，并且<strong>所有</strong> <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt;</code>, <code>=======</code>, <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code> 标记都必须被删除。</li></ol><p><strong>使用图形化工具解决冲突</strong></p><p>对于新手来说，使用 VS Code 或其他 IDE 内置的工具会让解决冲突变得非常直观。 当 VS Code 检测到冲突时，它会在冲突代码块的上方提供几个可点击的选项：</p><ul><li><strong><code>Accept Current Change</code></strong> (接受当前更改)：只保留 <code>HEAD</code> 的版本。</li><li><strong><code>Accept Incoming Change</code></strong> (接受传入的更改)：只保留另一个分支的版本。</li><li><strong><code>Accept Both Changes</code></strong> (接受双方的更改)：同时保留两者。</li><li><strong><code>Compare Changes</code></strong> (比较更改)：并排高亮显示差异。 点击这些选项，IDE 会自动为你修改文件，大大降低了手动编辑出错的概率。</li></ul><p><strong>“救命！我把冲突搞得一团糟！”——如何中止合并</strong></p><p>如果你在解决冲突的过程中感到困惑，或者不确定自己是否改对了，最好的办法就是<strong>中止合并</strong>，让仓库回到合并之前的状态。</p><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">命令</th><th style="text-align:left;">效果</th></tr></thead><tbody><tr><td style="text-align:left;">在 <code>git merge</code> 过程中</td><td style="text-align:left;"><code>git merge --abort</code></td><td style="text-align:left;">取消本次合并，你的工作目录会恢复到运行 <code>merge</code> 命令之前的状态。</td></tr><tr><td style="text-align:left;">在 <code>git rebase</code> 过程中</td><td style="text-align:left;"><code>git rebase --abort</code></td><td style="text-align:left;">取消本次变基，分支会回到变基之前的状态。</td></tr></tbody></table><p>这个命令非常安全，是你解决冲突时的“后悔药”。</p><p><strong>预防冲突的最佳实践</strong></p><p>虽然学会解决冲突很重要，但更好的方式是尽量避免它。</p><ul><li><strong>频繁更新</strong>：在开始一项新功能前，或在开发过程中，经常从主分支（如 <code>main</code>）<code>git pull</code> 或 <code>git rebase</code>，保持你的分支与主线同步。分歧越小，冲突的概率越低。</li><li><strong>小步提交</strong>：保持你的提交小而专注。一个提交只做一件事。这样即使有冲突，范围也会很小，容易解决。</li><li><strong>有效沟通</strong>：与你的团队成员沟通，了解彼此正在修改的模块，避免同时修改同一块核心代码。</li><li><strong>使用功能分支</strong>：严格遵守一人一分支的原则，不要直接在 <code>main</code> 或 <code>develop</code> 这种公共分支上直接开发。</li></ul>`,79)])])}const b=d(g,[["render",r]]);export{x as __pageData,b as default};
